/* =============================================================
   bible-timeline.js — Visual Bible Timeline data (F4-D, expanded)

   ~90 events from Creation to Revelation, ordered chronologically.
   Era IDs match the Bible Lands period overlays so events visually
   thread through the same color system as the map. The 'judges'
   era is unique to the timeline; 'second-temple' covers the
   intertestamental period.

   Years use BC negative / AD positive integer convention internally
   (year property), with displayYear for the rendered label. Pre-
   historical events get displayYear strings like "Beginning" or
   "~2400 BC".
============================================================= */

const BIBLE_TIMELINE_EVENTS = [
  // ── ACT 1: CREATION & PRE-HISTORY ─────────────────────────
  { id:'creation', year:-9999, displayYear:'Beginning', era:'patriarchs',
    icon:'🌌', title:'Creation',
    subtitle:'God speaks the universe into being.',
    body:`<p>"In the beginning, God created the heavens and the earth." Light from darkness. Water from sky. Land from sea. Plants from soil. Lights in the firmament. Fish in the deep, birds in the air, beasts on the ground. Each day God speaks, and the universe answers. He does not assemble matter — He calls things into being from nothing at all.</p><p>On the sixth day He stoops. From the dust He fashions a man, breathes His own breath into the nostrils, and image is born. Male and female are made in the likeness of the Trinity itself — designed for relationship, given dominion, blessed with work. The seventh day is set aside not from fatigue but from completion: the universe has its King, the King has His house, and rest enters time.</p><p>Every page that follows hangs from this opening. There is a Maker. There is a meaning. Matter is not eternal, evil is not necessary, and we are not accidents. The Bible begins with a wedding of heaven and earth — and the long story of Scripture is the rescue of that wedding after we ourselves break it.</p>`,
    whyMatters:`<p>You are not a cosmic mistake. The body in the mirror, the soul behind it, the day in front of you — all of it begins as gift, called into being by a Maker who delights in His work. To remember Creation is to remember that you were wanted before you were anything else.</p>`,
    keyVerse:{ ref:'Genesis 1:1', text:'In the beginning, God created the heavens and the earth.' },
    scriptureRefs:['Genesis 1','Genesis 2'], relatedStoryId:'creation' },
  { id:'fall', year:-9998, displayYear:'Eden', era:'patriarchs',
    icon:'🍎', title:'The Fall',
    subtitle:'Humanity chooses independence from God.',
    body:`<p>The garden is finished. The man and the woman walk with God in the cool of the day. One tree is forbidden — not because the fruit is poison, but because love requires a real choice. The serpent appears: subtle, smooth, twisting God's words by a single syllable. "Did God really say?" Doubt is planted before disobedience. Eve looks. The fruit is taken. Adam, standing silent beside her, eats too.</p><p>Eyes open. Shame arrives like a stranger they cannot turn away. They sew fig leaves; they hide in the bushes; they hear footsteps and run. God comes asking the saddest question in the Bible: "Where are you?" Curses fall on the serpent, on childbirth, on labor, on the ground itself. But within the curse, the first promise glimmers — a future Seed of the woman who will crush the serpent's head.</p><p>Eden's gate closes behind them. Cherubim with a flaming sword guard the way to the tree of life. Every aching thing about being human starts here — death, distance, distortion of every good gift. Yet every page after this is God walking toward us again, this time wearing skin.</p>`,
    whyMatters:`<p>The Fall explains why nothing in the world quite fits — including yourself. The longing for a goodness you can't manufacture, the failures that shock even you, the ache for home — these aren't proof you are broken beyond repair. They are proof you remember Eden, and the Gardener is coming back.</p>`,
    keyVerse:{ ref:'Genesis 3:15', text:'I will put enmity between you and the woman, and between your offspring and her offspring; he shall bruise your head, and you shall bruise his heel.' },
    scriptureRefs:['Genesis 3','Romans 5:12'], relatedStoryId:'the-fall' },
  { id:'flood', year:-2400, displayYear:'~2400 BC', era:'patriarchs',
    icon:'🌊', title:'The Flood',
    subtitle:'God resets through one faithful family.',
    body:`<p>Generations pass. By Noah's time, "every intention of the thoughts of the heart was only evil continually." God grieves that He made humanity. But Noah finds favor — one righteous man in a violent world — and God tells him to build a boat in the shape of a long wooden box, three hundred cubits by fifty by thirty, on dry land, hundreds of miles from any sea.</p><p>For decades Noah builds and warns. Neighbors mock. Skies stay clear. Then the springs of the deep burst open and the windows of heaven are thrown wide. Forty days and nights the water rises until the highest mountains disappear. Inside the ark: one family, two of every kind of creature, and a God who shut the door Himself. When the water finally falls, a raven goes out and does not return; a dove brings back an olive leaf.</p><p>Noah builds an altar on a new earth. The rainbow becomes the first sign attached to the first covenant — God promises never again to flood the world. The flood is not just punishment; it is reset, judgment and grace folded into the same rising water. Peter would later see the ark as a picture of baptism: salvation through judgment, on the other side of death.</p>`,
    whyMatters:`<p>The flood is uncomfortable because it tells the truth about evil — that God will not look the other way forever. And yet the same God who closes the sky also builds the boat. Wherever His judgment falls, His mercy has already gone ahead, hammering wood, opening a door.</p>`,
    keyVerse:{ ref:'Genesis 9:13', text:'I have set my bow in the cloud, and it shall be a sign of the covenant between me and the earth.' },
    scriptureRefs:['Genesis 6-9','2 Peter 2:5'], relatedStoryId:'noahs-ark' },
  { id:'babel', year:-2300, displayYear:'~2300 BC', era:'patriarchs',
    icon:'🗼', title:'Tower of Babel',
    subtitle:'Pride scatters humanity.',
    body:`<p>The descendants of Noah were told to fill the earth. Instead, they settle on a plain in Shinar and decide to stay together. They invent baked brick and bitumen. They lay out a city with a tower at the center "with its top in the heavens, that we may make a name for ourselves, lest we be dispersed."</p><p>The story is told tongue-in-cheek. God has to "come down" to see the tower humanity thinks is reaching Him. Pride is not stronger than mortar; it is also more dangerous. God responds with confusion — not punishment so much as kindness, splintering one language into many so that unified human ambition cannot do unlimited human damage. The city is left half-built. The people scatter into nations.</p><p>Every later confusion between peoples traces back here. So does the great reversal at Pentecost: tongues of fire on the heads of disciples, and suddenly Parthians, Medes, Elamites, and Romans all hear the gospel in their own dialect. What pride scattered, the Spirit gathers — not by erasing differences, but by making them sing the same song.</p>`,
    whyMatters:`<p>Every age has its tower. Every soul has its name to make. The Babel pattern lives in any project — including the spiritual ones — that uses God's gifts to climb past needing God Himself. The cure isn't smaller dreams; it's a Maker worth being known by.</p>`,
    keyVerse:{ ref:'Genesis 11:4', text:'Come, let us build ourselves a city and a tower with its top in the heavens, and let us make a name for ourselves.' },
    scriptureRefs:['Genesis 11:1-9'], relatedStoryId:'tower-babel' },

  // ── ACT 2: PATRIARCHS ─────────────────────────────────────
  { id:'abraham', year:-2000, displayYear:'~2000 BC', era:'patriarchs',
    icon:'⭐', title:"Abraham's Call",
    subtitle:'God promises a great nation through one man.',
    body:`<p>Centuries after Babel, in the city of Ur on the Euphrates, God speaks to a seventy-five-year-old man named Abram. No backstory of righteousness is given. No reason for the choice is offered. The call is simply: "Go from your country and your kindred and your father's house to the land that I will show you. And I will make of you a great nation, and I will bless you and make your name great, so that you will be a blessing."</p><p>The promise has three layers — a land, a people, and a blessing for all nations. Each is impossible: Abram has no son, his wife is barren, and the destination is unnamed. He goes anyway. The narrowing has begun. God will work through one family so the blessing can later widen to all the families of the earth. Through this old man and his eventual son will come the line of Isaac, Jacob, David, and finally Jesus.</p><p>Hebrews remembers him as the great example of faith: "By faith Abraham obeyed when he was called to go out to a place that he was to receive as an inheritance, and he went out, not knowing where he was going." Faith does not mean having a map. It means trusting the One who has one.</p>`,
    whyMatters:`<p>God still calls people who don't qualify. He still asks them to leave something they can see for something they can't. The blessings He hands out come with a wider purpose — through you, to others. The story you're part of is bigger than your story.</p>`,
    keyVerse:{ ref:'Genesis 12:2-3', text:'I will make of you a great nation, and I will bless you and make your name great, so that you will be a blessing... and in you all the families of the earth shall be blessed.' },
    scriptureRefs:['Genesis 12:1-3','Hebrews 11:8'], relatedSiteId:'shechem', relatedStoryId:'abrahams-covenant' },
  { id:'sodom', year:-1950, displayYear:'~1950 BC', era:'patriarchs',
    icon:'🔥', title:'Sodom & Gomorrah',
    subtitle:'Judgment falls; Abraham intercedes.',
    body:`<p>The cities of the plain — Sodom and Gomorrah and three others — have become bywords for cruelty. The outcry against them reaches heaven. God comes down to see; three travelers visit Abraham's tent on the way. After lunch under the oaks of Mamre, two of them turn toward the cities. The third stays to talk with Abraham.</p><p>What follows is one of Scripture's strangest and most tender scenes — a man bargaining with God over how many righteous people would be enough to save a city. Fifty? Forty-five? Forty? Thirty? Twenty? Ten? At every step God yields. Abraham learns something about the heart of the Judge: He is not eager to destroy; He is eager to spare. Ten righteous are not found. Lot and his daughters barely escape, his wife looks back and turns to salt, and fire rains down at sunrise.</p><p>Sodom is not destroyed for its inhospitality alone or its sexual sin alone; Ezekiel later names pride, gluttony, and a refusal to help the poor as core to its rot. The story is harder than slogans. Justice falls; mercy is offered first; intercession is heard. The God who would later let His own city walk past Him to a cross has always been negotiated with by anyone willing to ask.</p>`,
    whyMatters:`<p>If you have ever wondered whether God hears the cries of the abused or the prayers of the few, this story answers: yes. Justice is real; mercy is real; intercession is real. There is no city beyond rescue while there are still people willing to pray for it.</p>`,
    keyVerse:{ ref:'Genesis 18:25', text:'Shall not the Judge of all the earth do what is just?' },
    scriptureRefs:['Genesis 18:16-33','Genesis 19'] },
  { id:'isaac-binding', year:-1900, displayYear:'~1900 BC', era:'patriarchs',
    icon:'🐏', title:'The Binding of Isaac',
    subtitle:'God provides the substitute on Moriah.',
    body:`<p>Isaac is the long-awaited son — born when Abraham is a hundred and Sarah is ninety, laughed about by everyone including her, the living evidence that nothing is too hard for the Lord. Then comes the test no parent could imagine. "Take your son, your only son Isaac, whom you love, and go to the land of Moriah, and offer him there as a burnt offering on one of the mountains of which I shall tell you."</p><p>Three silent days of walking. At the foot of the mountain Abraham leaves the servants — "We will worship and come again to you." (We. Both of us. He already trusts that God can raise the dead, Hebrews tells us.) On the mountain Isaac asks the unbearable question: "Where is the lamb?" Abraham answers, "God will provide the lamb, my son." Wood is laid; the boy is bound; the knife rises.</p><p>The angel of the Lord cries from heaven. A ram is caught by its horns in a thicket. The substitute is provided — not because God didn't mean it, but because He always meant to provide Himself. The mountain is Moriah — the same hill where Solomon would later build the Temple, and where the city of Jerusalem would eventually surround the place where another Father, two thousand years later, would offer His only Son and not stop the knife.</p>`,
    whyMatters:`<p>God will ask you to hold the things you love most with open hands. He is not cruel; He is teaching you that He is enough — and that whatever He requires, He will provide. On the mountain where Abraham was spared, Another would not be. That is how seriously God meant the lamb.</p>`,
    keyVerse:{ ref:'Genesis 22:14', text:'So Abraham called the name of that place, The LORD will provide; as it is said to this day, On the mount of the LORD it shall be provided.' },
    scriptureRefs:['Genesis 22','Hebrews 11:17-19'], relatedStoryId:'abraham-isaac' },
  { id:'jacob-ladder', year:-1850, displayYear:'~1850 BC', era:'patriarchs',
    icon:'🪜', title:"Jacob's Ladder",
    subtitle:'Heaven and earth meet at Bethel.',
    body:`<p>Jacob has just deceived his father, stolen his brother's blessing, and fled north with nothing but a staff. The first night on the run he sleeps in the open with a stone for a pillow — the kind of bed a guilty man earns. There, in the dirt, God meets him.</p><p>He dreams of a stairway reaching from earth to heaven with the angels of God ascending and descending on it. At the top stands the Lord Himself, who renews to Jacob every promise He gave to Abraham and Isaac — the land, the offspring, the blessing for all peoples, and one more line: "Behold, I am with you and will keep you wherever you go." Grace, before repentance. Promise, before performance.</p><p>Jacob wakes shaken. He sets up the stone as a pillar, pours oil on it, and names the place Bethel — "house of God." Centuries later, Jesus would tell Nathanael, "You will see heaven opened, and the angels of God ascending and descending on the Son of Man." The ladder was always a Person. Wherever Christ is, the gap between earth and heaven has been closed.</p>`,
    whyMatters:`<p>You can be running from God when He meets you. Bethel says you don't have to climb to heaven; heaven has already let down a stairway. The connection between you and God isn't built from the bottom up — it was built from the top down, in the shape of a cross.</p>`,
    keyVerse:{ ref:'Genesis 28:16', text:'Surely the LORD is in this place, and I did not know it.' },
    scriptureRefs:['Genesis 28:10-22','John 1:51'], relatedSiteId:'bethel', relatedStoryId:'jacob-esau' },
  { id:'jacob-wrestles', year:-1830, displayYear:'~1830 BC', era:'patriarchs',
    icon:'💪', title:'Jacob Wrestles God',
    subtitle:'A new name for a wounded man.',
    body:`<p>Twenty years later. Jacob has worked for his uncle Laban, married two sisters, fathered twelve children, and accumulated wealth. But he must finally face Esau — the brother he cheated, who is coming to meet him with four hundred men. Jacob sends gifts ahead. He divides his family for safety. Then, alone at the brook Jabbok at night, a man wrestles with him until daybreak.</p><p>It is not even a fair fight. The stranger could clearly end it at any moment; instead He waits. As dawn approaches He touches Jacob's hip and dislocates it with a touch. Even then Jacob refuses to let go: "I will not let you go unless you bless me." The blessing comes in the form of a new name. "Your name shall no longer be called Jacob — heel-grabber, supplanter — but Israel, for you have striven with God and with men, and have prevailed."</p><p>He limps away into the rising sun with a new name, a new identity, and a permanent reminder. Every patriarch in Scripture is bent before he is named. The same God who blesses you will first wound you in the place you would otherwise have used to fight Him. Israel — the whole nation, named after this night — is not a strong people. It is a limping people who have refused to let go.</p>`,
    whyMatters:`<p>The thing you wrestle with in the dark may turn out to be the One who is trying to bless you. Sometimes God's grip looks like a fight, and the limp He leaves behind is the proof you actually met Him. Don't let go before the blessing comes.</p>`,
    keyVerse:{ ref:'Genesis 32:26', text:'I will not let you go unless you bless me.' },
    scriptureRefs:['Genesis 32:22-32'] },
  { id:'joseph-egypt', year:-1700, displayYear:'~1700 BC', era:'patriarchs',
    icon:'👑', title:'Joseph in Egypt',
    subtitle:'God works evil into rescue.',
    body:`<p>Jacob's favorite son. Eleven brothers, one coat of many colors, two dreams of sheaves and stars bowing down to him. The family fault lines crack open. Joseph is thrown into a pit, then sold to a passing caravan, then resold to Potiphar, an officer of Pharaoh. He rises in Potiphar's house. Then Potiphar's wife lies about him and he is thrown into prison, forgotten there for years.</p><p>In prison he interprets two dreams — one for the cupbearer who is restored, one for the baker who is hanged. Two more years pass before Pharaoh dreams of seven fat cows and seven lean ones, seven full heads of grain and seven thin. Joseph is summoned, interprets, and the dungeon-boy stands before the most powerful man in the world by morning. He becomes second-in-command of Egypt, stockpiles grain through seven years of plenty, and feeds the known world through seven years of famine.</p><p>His brothers come down for bread, not recognizing the dignitary they bow to. After tests of their changed hearts, Joseph reveals himself in tears: "I am Joseph your brother, whom you sold into Egypt. And now do not be distressed... for God sent me before you to preserve life... You meant evil against me, but God meant it for good." The family of Israel survives, by way of an Egyptian palace, because a young man in a pit refused to stop trusting.</p>`,
    whyMatters:`<p>God writes long sentences. The pit and the prison were not detours from Joseph's calling — they were the road to it. If your present feels like waiting in a place no one remembers, you may be exactly where the story needs you to be. He will reveal Himself in His time.</p>`,
    keyVerse:{ ref:'Genesis 50:20', text:'As for you, you meant evil against me, but God meant it for good, to bring it about that many people should be kept alive, as they are today.' },
    scriptureRefs:['Genesis 37','Genesis 50:20'], relatedStoryId:'joseph' },

  // ── ACT 3: EXODUS & CONQUEST ──────────────────────────────
  { id:'burning-bush', year:-1447, displayYear:'~1447 BC', era:'exodus-conquest',
    icon:'🌿', title:'The Burning Bush',
    subtitle:'God names Himself: I AM.',
    body:`<p>Four hundred years of silence. Israel's family has grown into a nation of slaves in Egypt, groaning under brick quotas. Moses — once an Egyptian prince, then a murderer, now a fugitive — is eighty years old, herding his father-in-law's sheep on the back side of the wilderness. The dream of rescuing his people is decades dead.</p><p>A bush on Mount Horeb catches fire and does not burn down. Moses turns aside to see this strange sight — and out of the flame comes the voice that will reshape the next forty years of his life. "Take off your sandals, for the place where you are standing is holy ground." God names His grief over His people. He commissions Moses to go back to Egypt. Moses argues five times — Who am I? Who shall I say sent me? They won't believe me. I am slow of speech. Send someone else — and every time God answers.</p><p>The answer to "Who shall I say sent me?" is the most important name in Scripture: I AM WHO I AM. Not a god who came into being, not a god who depends on anyone else, not a god who could be otherwise. Pure being. Self-existent. The Sender does not need a sender. With that name burning in his memory, Moses turns back toward Egypt with his brother Aaron and a wooden staff.</p>`,
    whyMatters:`<p>God still meets people on the back side of the wilderness, where they thought their useful years were over. Holy ground is wherever He shows up — even at a bush no one else would have noticed. If you have argued with His call, you are in good company. The bush is still burning.</p>`,
    keyVerse:{ ref:'Exodus 3:14', text:'God said to Moses, I AM WHO I AM. And he said, Say this to the people of Israel, I AM has sent me to you.' },
    scriptureRefs:['Exodus 3','Exodus 4'], relatedStoryId:'burning-bush' },
  { id:'exodus', year:-1446, displayYear:'~1446 BC', era:'exodus-conquest',
    icon:'🔥', title:'The Exodus',
    subtitle:'God rescues Israel from Egypt.',
    body:`<p>Moses stands before Pharaoh with a wooden staff: "Let my people go, that they may serve me in the wilderness." Pharaoh sneers. Ten plagues follow, each one a direct strike at an Egyptian god — the Nile turned to blood (defeating Hapi), frogs (Heqet), flies, livestock, boils, hail, locusts, darkness over the land of the sun-god Ra. With every plague Pharaoh hardens, and Egypt is taken apart slowly.</p><p>The final plague is the Passover. Every household in Israel slaughters a lamb without blemish, paints the blood on the doorframes, eats the meat with bitter herbs and unleavened bread, ready to walk. At midnight the angel of death moves through Egypt; every firstborn son dies — Pharaoh's heir, the cattle's first calf, the prisoner's son — except where the blood marks the door. By dawn Pharaoh is screaming at Moses to leave.</p><p>Two million slaves march out, jewelry pressed into their hands by terrified neighbors. Pharaoh changes his mind and chases them with six hundred chariots. They are trapped at the Red Sea. Moses lifts his staff; the wind blows all night; the waters stand up in walls; Israel walks across on dry ground. When the Egyptians follow, the walls collapse. Miriam picks up a tambourine on the far shore and starts to sing. They will sing about this for three thousand years.</p>`,
    whyMatters:`<p>The Passover lamb still stands at the door. Every escape from death in Scripture rhymes with this night. The God who heard groaning in Egypt is still the God who hears it in your kitchen, your hospital room, your prison cell. He moves on schedule, not yours, but He moves.</p>`,
    keyVerse:{ ref:'Exodus 14:14', text:'The LORD will fight for you, and you have only to be silent.' },
    scriptureRefs:['Exodus 12','Exodus 14'], relatedStoryId:'plagues-red-sea' },
  { id:'sinai-law', year:-1446, displayYear:'~1446 BC', era:'exodus-conquest',
    icon:'📜', title:'The Law at Sinai',
    subtitle:'Rescued people receive their identity.',
    body:`<p>Three months out from Egypt the people camp in the wilderness of Sinai at the foot of a mountain. God tells Moses to consecrate the people for three days. On the morning of the third day, thunder and lightning crash, a thick cloud covers the mountain, a trumpet blast grows louder and louder, and the whole mountain trembles like a drumhead. The people stand at a distance, terrified.</p><p>Out of the cloud comes the Voice. Ten commandments — the first four about love for God, the last six about love for neighbor — written by the finger of God on tablets of stone. Around those ten, a whole code of justice unfolds: how to treat the foreigner, the widow, the slave, the enemy's lost ox. Israel will become a kingdom of priests, a holy nation, a people whose ordinary life is meant to display the character of their God to the world.</p><p>The Law was never the way to earn God's love — He had already rescued them from slavery before He gave them a single command. It was the shape of life with the God who had already saved them. Centuries later, Jesus would say He came not to abolish the Law but to fulfill it; Paul would say it was a tutor leading us to Christ. The mountain shakes here for a reason: a holy God has entered into covenant with a forgiven people.</p>`,
    whyMatters:`<p>Rescue comes first; rules come second. God doesn't hand you commandments so you can earn your way into His family. He's already pulled you out of Egypt. The Law is His way of saying, "Now here's how my children live free."</p>`,
    keyVerse:{ ref:'Exodus 20:2-3', text:'I am the LORD your God, who brought you out of the land of Egypt, out of the house of slavery. You shall have no other gods before me.' },
    scriptureRefs:['Exodus 19','Exodus 20'], relatedSiteId:'mt-sinai', relatedStoryId:'ten-commandments' },
  { id:'golden-calf', year:-1446, displayYear:'~1446 BC', era:'exodus-conquest',
    icon:'🐂', title:'The Golden Calf',
    subtitle:'Worship collapses while Moses is on the mountain.',
    body:`<p>Moses is on the mountain forty days receiving the Law. Down at the base, the people grow restless. He has been gone too long. The God of thunder feels far away. They go to Aaron — Moses' brother, the priest-in-training — and demand: "Make us gods who shall go before us." Aaron asks for their gold earrings. He melts them down and shapes a calf, builds an altar before it, and announces: "Tomorrow shall be a feast to the LORD."</p><p>The morning is a riot — sacrifice, eating, drinking, and the kind of celebration God specifically forbade. Moses comes down the mountain with the tablets in his hands. When he sees the calf and the dancing, he smashes the tablets at the foot of the mountain. He grinds the calf to powder, scatters it on the water, and makes the people drink. Three thousand fall that day. Moses goes back up the mountain alone and pleads — "If you will, forgive their sin; but if not, please blot me out of your book." God says no, He will not blot Moses out, but neither has He abandoned the people.</p><p>The golden calf is a warning that runs through the rest of Scripture: even right after rescue, even at the base of God's own mountain, the human heart cannot wait. We invent gods we can manage. The God who has just spoken from fire becomes a calf we can carry. The cost is high, but the covenant is not over. God will come down again — this time so close that no one will ever again confuse Him with metal.</p>`,
    whyMatters:`<p>The idol you make is always smaller than the God you're avoiding. When God feels slow, the temptation is to manufacture something visible. Wait for Him instead — He is coming down with the real thing, not a melted-gold copy.</p>`,
    keyVerse:{ ref:'Exodus 32:31-32', text:'Alas, this people has sinned a great sin. They have made for themselves gods of gold. But now, if you will forgive their sin — but if not, please blot me out of your book that you have written.' },
    scriptureRefs:['Exodus 32'] },
  { id:'tabernacle', year:-1445, displayYear:'~1445 BC', era:'exodus-conquest',
    icon:'⛺', title:'The Tabernacle Built',
    subtitle:'God dwells in the middle of His people.',
    body:`<p>God gives Moses detailed plans on the mountain — not for a city or an army, but for a tent. Acacia wood overlaid with gold. Curtains of blue and purple and scarlet linen. A bronze altar for sacrifice. A bronze basin for washing. A golden lampstand. A table of showbread. An altar of incense. And, in the innermost chamber behind a thick veil, the Ark of the Covenant — a gold-plated box holding the tablets of the Law, topped with two cherubim of beaten gold whose wings nearly touch.</p><p>For months the whole camp gives. Gold, silver, bronze, dyed yarn, ram skins, acacia poles, precious stones — given so freely that Moses eventually has to tell them to stop. The skilled craftsmen Bezalel and Oholiab work with a Spirit-given wisdom. On the first day of the first month of the second year, the tabernacle is finished. Moses sets it up, and the cloud descends, and the glory of the LORD fills the tent so thickly that even Moses cannot enter.</p><p>God is now living in the middle of His people. Not on a mountain at a distance, but in a tent at the center of the camp, moving with them wherever they go. Every detail of the tabernacle foreshadows something Christ will fulfill: the lamb, the bread, the light, the priest, the veil. John would later write of Jesus, "The Word became flesh and tabernacled among us" — using the exact word for this tent.</p>`,
    whyMatters:`<p>God's preferred address is not a palace; it is the middle of His people. Wherever the church gathers, wherever a believer prays, wherever a soul says yes — He pitches His tent. You do not have to climb a mountain to find Him. He has moved in.</p>`,
    keyVerse:{ ref:'Exodus 40:34', text:'Then the cloud covered the tent of meeting, and the glory of the LORD filled the tabernacle.' },
    scriptureRefs:['Exodus 25','Exodus 40:34-38'] },
  { id:'twelve-spies', year:-1445, displayYear:'~1445 BC', era:'exodus-conquest',
    icon:'🍇', title:'The Twelve Spies',
    subtitle:'Ten see giants. Two see God.',
    body:`<p>One year of camping at Sinai. Now Israel sits at the edge of the Promised Land — Kadesh-barnea, in the wilderness of Paran. God tells Moses to send twelve men, one from each tribe, to scout out the land. They go for forty days. They cut a single cluster of grapes so heavy two men carry it on a pole. They walk the cities and watch the people.</p><p>Ten come back terrified. "The land flows with milk and honey, but the people are stronger than we are. We saw giants there. We were like grasshoppers in our own sight, and so we were in theirs." Joshua and Caleb cut against the report: "Do not rebel against the LORD. Their protection is removed from them. The LORD is with us; do not fear them." The crowd picks the ten. They weep all night. They talk about choosing a new leader and going back to Egypt.</p><p>God's verdict is severe. The generation that just walked through the Red Sea will not enter the land. They will wander forty years — one for each day the spies were gone — until every adult unbeliever has died in the wilderness. Only Joshua and Caleb, and the children whom the parents feared could not survive, will inherit the promise. The cost of unbelief is never just a delay; it is sometimes an entire generation.</p>`,
    whyMatters:`<p>God shows you the land before He gives it to you. The question is what you'll do with the giants. Faith doesn't pretend the obstacles aren't real; it remembers Who is bigger than they are. Don't let fear write you out of a promise that was already meant for you.</p>`,
    keyVerse:{ ref:'Numbers 14:8', text:'If the LORD delights in us, he will bring us into this land and give it to us, a land that flows with milk and honey.' },
    scriptureRefs:['Numbers 13','Numbers 14'] },
  { id:'bronze-serpent', year:-1407, displayYear:'~1407 BC', era:'exodus-conquest',
    icon:'🐍', title:'The Bronze Serpent',
    subtitle:'Look and live.',
    body:`<p>Late in the forty years of wandering. The shortcut around Edom is long and hot and the people break, again. "Why have you brought us up out of Egypt to die in the wilderness? There is no food and no water, and we loathe this worthless food." Manna is "worthless food" now — the same bread of heaven they once cried out for. God sends fiery serpents into the camp. People are bitten. Many die.</p><p>The people repent. They ask Moses to pray. Moses prays. God's answer is strange — not antivenom, not removal of the snakes, but a sign. "Make a fiery serpent and set it on a pole, and everyone who is bitten, when he sees it, shall live." Moses fashions a serpent of bronze and lifts it up on a pole in the middle of the camp. Anyone bitten who turned their head to look — lived.</p><p>Fifteen hundred years later Jesus, talking with Nicodemus in the dark, would point straight back to this moment: "As Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up, that whoever believes in him may have eternal life." The sin-serpent dies on a pole. Whoever looks, lives. The cross is in the desert long before it's in Jerusalem.</p>`,
    whyMatters:`<p>Salvation is not earned by what you do. It is received by where you look. The most active soul in the room is the one bitten and dying who turns its head toward the Lifted One. Look at Him. You will live.</p>`,
    keyVerse:{ ref:'John 3:14-15', text:'And as Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up, that whoever believes in him may have eternal life.' },
    scriptureRefs:['Numbers 21:4-9','John 3:14-15'] },
  { id:'moses-death', year:-1406, displayYear:'~1406 BC', era:'exodus-conquest',
    icon:'🏔️', title:'Death of Moses',
    subtitle:'A leader sees the land but does not enter.',
    body:`<p>Forty years of wandering are over. The new generation stands at the eastern bank of the Jordan, looking across at Jericho. Moses is one hundred and twenty years old. Three times in Deuteronomy he preaches the Law one last time to a people about to enter the land. He sings a final song, blesses each of the tribes, and then God tells him to climb Mount Nebo.</p><p>From the top, God shows him the whole land — Gilead to Dan, Naphtali, Ephraim and Manasseh, Judah, the Negev, the plain of Jericho, all the way to the western sea. "This is the land of which I swore to Abraham, to Isaac, and to Jacob, saying, 'I will give it to your offspring.' I have let you see it with your eyes, but you shall not go over there." Years earlier Moses had struck a rock in anger when God told him to speak to it; this is the price. He sees from a distance what he will not enter.</p><p>Moses dies on the mountain, and the Lord buries him in the valley — no one knows the place to this day. Israel mourns for thirty days. Joshua takes up the staff. Centuries later, on a different mountain, Moses appears beside Elijah talking with Jesus about the exodus Jesus is about to accomplish in Jerusalem. He sees the Promised Land after all.</p>`,
    whyMatters:`<p>Not every promise lands in the timeline you imagined. Some of the most faithful saints see the land but do not enter it. God keeps His word — but His timing is His own. Faithfulness is finishing well even when someone else carries the work forward.</p>`,
    keyVerse:{ ref:'Deuteronomy 34:10', text:'There has not arisen a prophet since in Israel like Moses, whom the LORD knew face to face.' },
    scriptureRefs:['Deuteronomy 34'] },
  { id:'conquest', year:-1406, displayYear:'~1406 BC', era:'exodus-conquest',
    icon:'⚔️', title:'Joshua Crosses the Jordan',
    subtitle:'Forty years end at the Promised Land.',
    body:`<p>Joshua, formerly Moses' aide, now leads. God's first command to him is repeated four times in the opening chapter: "Be strong and courageous." Three days of preparation. Two spies sent to Jericho. Then on the morning of the crossing, the priests step into the Jordan carrying the Ark of the Covenant — the river is at flood stage from the spring melt — and the moment their feet touch the water, the river stops upstream at the city of Adam, and the riverbed stands dry.</p><p>The whole nation crosses, two million strong, while the priests stand mid-river. Twelve stones are carried out and set up on the western bank as a memorial — "When your children ask in time to come, 'What do these stones mean?' you shall let your children know, 'Israel crossed over this Jordan on dry ground.'" The river runs again behind them. There is no going back. Egypt is over. The wilderness is over. The land of promise is finally under their feet.</p><p>Forty years before, the parents had refused to cross. Now the children do. Every generation must decide for itself whether to walk into what God has prepared. The God who parted the Red Sea also parted the Jordan — different rivers, same word: nothing can stand between a faithful God and the people He is bringing home.</p>`,
    whyMatters:`<p>The thresholds in your life — the new job, the new marriage, the new step of obedience — usually look like floodwater. God's habit is to part the water as you step in, not before. The promise is on the other side, and the river always runs again behind you.</p>`,
    keyVerse:{ ref:'Joshua 1:9', text:'Have I not commanded you? Be strong and courageous. Do not be frightened, and do not be dismayed, for the LORD your God is with you wherever you go.' },
    scriptureRefs:['Joshua 3','Joshua 4'], relatedSiteId:'jericho', relatedStoryId:'jericho' },
  { id:'jericho-walls', year:-1406, displayYear:'~1406 BC', era:'exodus-conquest',
    icon:'🏛️', title:'The Walls of Jericho',
    subtitle:'Worship is the battle plan.',
    body:`<p>The first city in the land. Jericho's walls were thick enough to drive a chariot on top of, and the city had been there for thousands of years. Joshua is met outside the walls by the commander of the army of the Lord — sword drawn, on neither side, but God's side. Joshua falls on his face. He is told to take off his sandals, just as Moses was at the bush. This battle, like Sinai, is holy ground.</p><p>The plan is absurd. For six days the army is to circle the city once, in silence, with seven priests blowing rams' horns in front of the Ark. On the seventh day they are to circle seven times, and then on the seventh circle of the seventh day, when the priests blow a long blast, the people are to shout. That is the entire strategy. Worship is the battle plan. Trumpets, not siege engines. A shout, not a ram.</p><p>Six days pass. The morning of the seventh day comes. Seven slow circles, in the quiet of dawn. The long blast. The shout of a nation. And the wall, which had stood for centuries, falls down flat — straight down, not toppled outward — so that every soldier walks straight up over the rubble into the city. Rahab the prostitute and her family are spared. She marries an Israelite named Salmon and becomes part of the line that leads to David, and through David, to Jesus.</p>`,
    whyMatters:`<p>The walls that have stood for years in your life — the addictions, the unforgiveness, the family patterns — do not fall to your strength. They fall to obedience and worship done on repeat. Show up. Walk the circle. The seventh day is closer than you think.</p>`,
    keyVerse:{ ref:'Hebrews 11:30', text:'By faith the walls of Jericho fell down after they had been encircled for seven days.' },
    scriptureRefs:['Joshua 6','Hebrews 11:30'], relatedSiteId:'jericho', relatedStoryId:'jericho' },
  { id:'sun-stands', year:-1400, displayYear:'~1400 BC', era:'exodus-conquest',
    icon:'☀️', title:'The Sun Stands Still',
    subtitle:'God fights for Israel at Gibeon.',
    body:`<p>In battle against five Amorite kings, Joshua prays for daylight to finish the rout. The sun halts in the sky for nearly a full day. "There has never been a day like it before or since, when the LORD listened to a human voice."</p>`,
    scriptureRefs:['Joshua 10:12-14'] },

  // ── ACT 4: JUDGES ─────────────────────────────────────────
  { id:'judges-cycle', year:-1380, displayYear:'~1380 BC', era:'judges',
    icon:'🌀', title:'The Cycle of Judges Begins',
    subtitle:'A repeating pattern of forgetting and rescue.',
    body:`<p>Israel forgets, suffers under oppressors, cries out, gets rescued by a raised-up deliverer, forgets again. The book ends with the haunting line: "Everyone did what was right in his own eyes."</p>`,
    scriptureRefs:['Judges 2:10-19','Judges 21:25'] },
  { id:'deborah', year:-1200, displayYear:'~1200 BC', era:'judges',
    icon:'🌳', title:'Deborah & Barak',
    subtitle:'A prophetess leads under the palm tree.',
    body:`<p>Deborah judges Israel from beneath a palm tree. She summons Barak to face Sisera's nine hundred iron chariots. Victory comes — and Jael drives the tent peg. Deborah's song becomes one of Scripture's oldest poems.</p>`,
    scriptureRefs:['Judges 4','Judges 5'] },
  { id:'gideon', year:-1170, displayYear:'~1170 BC', era:'judges',
    icon:'🐏', title:"Gideon's Fleece",
    subtitle:'A frightened man becomes a warrior.',
    body:`<p>Gideon hides from Midianites in a winepress when the angel calls him "mighty warrior." After two fleece-tests for assurance, God whittles his army from 32,000 to 300 — so the victory is unmistakably His.</p>`,
    scriptureRefs:['Judges 6','Judges 7'] },
  { id:'ruth', year:-1100, displayYear:'~1100 BC', era:'judges',
    icon:'🌾', title:'Ruth & Boaz',
    subtitle:'Loyalty writes its way into the messianic line.',
    body:`<p>A Moabite widow refuses to leave her Israelite mother-in-law: "Where you go I will go, your God my God." She gleans Boaz's barley field. He becomes her redeemer. Their grandson is Jesse — father of David.</p>`,
    scriptureRefs:['Ruth 1:16-17','Matthew 1:5'] },
  { id:'samson', year:-1085, displayYear:'~1085 BC', era:'judges',
    icon:'💪', title:'Samson & Delilah',
    subtitle:'Strength wasted, then redeemed at the end.',
    body:`<p>A Nazirite from birth, Samson tears lions apart and breaks armies — but his weakness for Philistine women undoes him. Blinded and humiliated, he prays once more and brings the temple of Dagon down on his enemies.</p>`,
    scriptureRefs:['Judges 13','Judges 16:23-30'] },
  { id:'hannah', year:-1080, displayYear:'~1080 BC', era:'judges',
    icon:'🙏', title:"Hannah's Prayer",
    subtitle:'A bitter woman births a prophet.',
    body:`<p>Childless and mocked, Hannah pours out her soul at the tabernacle in Shiloh — lips moving without sound. Eli the priest thinks she's drunk. God gives her a son: Samuel, who will anoint Israel's first kings.</p>`,
    scriptureRefs:['1 Samuel 1','1 Samuel 2:1-10'] },
  { id:'samuel-anoints', year:-1050, displayYear:'~1050 BC', era:'judges',
    icon:'🕯️', title:'Samuel — The Last Judge',
    subtitle:'A boy hears God in the dark.',
    body:`<p>"Speak, LORD, for your servant is listening." Samuel grows into Israel's last judge and a kingmaker. When the elders demand a human king "like the nations," God says: they have rejected Me, not you.</p>`,
    scriptureRefs:['1 Samuel 3','1 Samuel 8'] },

  // ── ACT 5: UNITED KINGDOM ────────────────────────────────
  { id:'saul-crowned', year:-1050, displayYear:'~1050 BC', era:'united-kingdom',
    icon:'👑', title:'Saul, the First King',
    subtitle:'Tall, hidden, then crowned.',
    body:`<p>Samuel anoints Saul — head and shoulders above any Israelite, found hiding among the baggage at his own coronation. He starts well, then chooses fear over obedience. The kingdom is torn from his line.</p>`,
    scriptureRefs:['1 Samuel 10','1 Samuel 15'] },
  { id:'goliath', year:-1025, displayYear:'~1025 BC', era:'united-kingdom',
    icon:'🪨', title:'David & Goliath',
    subtitle:'A shepherd boy and five smooth stones.',
    body:`<p>For forty days the Philistine giant taunts Israel. A teenage David, errand-running for his brothers, asks the question no one else dares: "Who is this uncircumcised Philistine to defy the armies of the living God?" One stone. One stunned army. One nation's hero is born.</p>`,
    scriptureRefs:['1 Samuel 17'] },
  { id:'david', year:-1010, displayYear:'~1010 BC', era:'united-kingdom',
    icon:'👑', title:'King David',
    subtitle:"A man after God's own heart, flawed and forgiven.",
    body:`<p>Shepherd boy to king. Psalms, conquest, the unified kingdom centered in Jerusalem. The covenant: "Your throne shall be established forever" — fulfilled in Jesus, Son of David.</p>`,
    scriptureRefs:['1 Samuel 16','2 Samuel 7'], relatedSiteId:'jerusalem' },
  { id:'ark-jerusalem', year:-1000, displayYear:'~1000 BC', era:'united-kingdom',
    icon:'📦', title:'The Ark Comes to Jerusalem',
    subtitle:'A king dances before God in the streets.',
    body:`<p>David brings the Ark of the Covenant up to his new capital with shouts and trumpets, dancing "with all his might." Michal despises him from a window. God's presence has come home to His city.</p>`,
    scriptureRefs:['2 Samuel 6'] },
  { id:'bathsheba', year:-990, displayYear:'~990 BC', era:'united-kingdom',
    icon:'💔', title:"David's Sin & Repentance",
    subtitle:'The greater the man, the deeper the fall.',
    body:`<p>A rooftop glance becomes adultery, then murder. Nathan the prophet confronts: "You are the man." David writes Psalm 51 — "Create in me a clean heart, O God." Forgiven; consequences still fall on his house.</p>`,
    scriptureRefs:['2 Samuel 11','2 Samuel 12','Psalm 51'] },
  { id:'solomon-crowned', year:-970, displayYear:'~970 BC', era:'united-kingdom',
    icon:'⚖️', title:'Solomon Asks for Wisdom',
    subtitle:'God offers anything. He asks for understanding.',
    body:`<p>In a dream at Gibeon, God says: "Ask what I shall give you." Solomon asks for a discerning heart to govern. God grants wisdom — and adds wealth and honor besides. The two prostitutes and the baby prove the gift soon after.</p>`,
    scriptureRefs:['1 Kings 3'] },
  { id:'solomon-temple', year:-957, displayYear:'~957 BC', era:'united-kingdom',
    icon:'🏛️', title:"Solomon's Temple",
    subtitle:'Heaven and earth meet on Mount Moriah.',
    body:`<p>Seven years to build. Cedar from Lebanon. Gold from Ophir. The Ark in the Holy of Holies behind a thick veil. God's glory fills the house as a visible cloud — so dense the priests cannot stand to serve.</p>`,
    scriptureRefs:['1 Kings 6','1 Kings 8'], relatedSiteId:'temple-mount' },
  { id:'queen-sheba', year:-950, displayYear:'~950 BC', era:'united-kingdom',
    icon:'💎', title:'The Queen of Sheba',
    subtitle:'Wisdom that reaches the ends of the earth.',
    body:`<p>From the south she comes with hard questions and a camel train of spices. Solomon answers them all. She leaves saying: "Not half was told me. Blessed is the LORD your God." Jesus would later cite her judgment on His own generation.</p>`,
    scriptureRefs:['1 Kings 10','Matthew 12:42'] },

  // ── ACT 6: DIVIDED KINGDOM ────────────────────────────────
  { id:'kingdom-split', year:-930, displayYear:'~930 BC', era:'divided-kingdom',
    icon:'⚡', title:'The Kingdom Splits',
    subtitle:'North (Israel) vs. South (Judah).',
    body:`<p>Solomon's son Rehoboam refuses to lighten the load. Ten tribes break off under Jeroboam. Two kingdoms, two paths, both drifting from God. The Davidic line continues only in Judah.</p>`,
    scriptureRefs:['1 Kings 12'] },
  { id:'jeroboam-calves', year:-930, displayYear:'~930 BC', era:'divided-kingdom',
    icon:'🐂', title:"Jeroboam's Golden Calves",
    subtitle:'Politics builds rival worship.',
    body:`<p>Afraid his people will return to Jerusalem for festivals, Jeroboam sets up golden calves at Dan and Bethel: "Here are your gods, Israel." The northern kingdom's spiritual fracture is permanent.</p>`,
    scriptureRefs:['1 Kings 12:25-33'] },
  { id:'elijah', year:-870, displayYear:'~870 BC', era:'divided-kingdom',
    icon:'🔥', title:'Elijah on Mount Carmel',
    subtitle:'Fire falls. Baal loses.',
    body:`<p>Four hundred fifty prophets of Baal. One Elijah. A drenched offering. The day-long pleading to silent gods. Then Elijah prays once and heaven answers with fire. The people fall on their faces — "The LORD, He is God."</p>`,
    scriptureRefs:['1 Kings 18:20-40'], relatedSiteId:'mt-carmel' },
  { id:'naboth', year:-860, displayYear:'~860 BC', era:'divided-kingdom',
    icon:'🍇', title:"Naboth's Vineyard",
    subtitle:"A king's covetousness becomes a queen's murder.",
    body:`<p>Ahab sulks because Naboth refuses to sell his family vineyard. Jezebel arranges false witnesses and a stoning. Elijah delivers God's verdict: "Where dogs licked Naboth's blood, they will lick yours."</p>`,
    scriptureRefs:['1 Kings 21'] },
  { id:'elisha', year:-850, displayYear:'~850 BC', era:'divided-kingdom',
    icon:'🌊', title:"Elisha's Double Portion",
    subtitle:"The prophet's mantle keeps falling.",
    body:`<p>Chariots of fire take Elijah up in a whirlwind. Elisha picks up the mantle and parts the Jordan in turn. His ministry overflows with mercy miracles — widow's oil multiplied, Naaman cleansed of leprosy, a dead boy raised.</p>`,
    scriptureRefs:['2 Kings 2','2 Kings 5'] },
  { id:'jonah', year:-785, displayYear:'~785 BC', era:'divided-kingdom',
    icon:'🐋', title:'Jonah & Nineveh',
    subtitle:'A reluctant prophet, a repenting city.',
    body:`<p>Sent to Israel's worst enemy, Jonah runs. A storm, a fish, three days in the dark. Then the city of 120,000 repents at his eight-word sermon — and Jonah is angry that God is merciful. The book ends with a question only the reader can answer.</p>`,
    scriptureRefs:['Jonah 1','Jonah 4'] },
  { id:'amos-hosea', year:-760, displayYear:'~760 BC', era:'divided-kingdom',
    icon:'📯', title:'Amos & Hosea',
    subtitle:'Justice and faithful love, side by side.',
    body:`<p>Amos thunders at the rich who "trample on the heads of the poor." Hosea marries a prostitute as a living parable: God's people prostitute themselves to other gods, yet He keeps loving and buying her back.</p>`,
    scriptureRefs:['Amos 5:24','Hosea 11:1-4'] },
  { id:'isaiah', year:-740, displayYear:'~740 BC', era:'divided-kingdom',
    icon:'📯', title:'Isaiah Prophesies the Messiah',
    subtitle:'A virgin, a child, a suffering servant.',
    body:`<p>"For unto us a Child is born... Wonderful Counselor, Mighty God, Everlasting Father, Prince of Peace." Isaiah 53 sketches the cross seven hundred years early — pierced for our transgressions, crushed for our iniquities.</p>`,
    scriptureRefs:['Isaiah 9:6','Isaiah 53'] },
  { id:'samaria-falls', year:-722, displayYear:'722 BC', era:'divided-kingdom',
    icon:'💥', title:'Northern Kingdom Falls',
    subtitle:'Assyria scatters Israel.',
    body:`<p>Assyria sweeps through. The ten northern tribes are exiled, deported, and scattered. Foreigners are resettled in their land. Only Judah remains — and she has been warned.</p>`,
    scriptureRefs:['2 Kings 17'] },
  { id:'hezekiah-tunnel', year:-701, displayYear:'701 BC', era:'divided-kingdom',
    icon:'💧', title:"Hezekiah's Tunnel",
    subtitle:'Sennacherib besieges; God delivers.',
    body:`<p>Hezekiah cuts a 1,750-foot tunnel through bedrock to hide Jerusalem's water from the Assyrians. Sennacherib mocks the LORD. The angel of the LORD strikes 185,000 Assyrian soldiers in a single night.</p>`,
    scriptureRefs:['2 Kings 18-19','2 Chronicles 32'] },
  { id:'josiah-book', year:-621, displayYear:'621 BC', era:'divided-kingdom',
    icon:'📖', title:'Josiah Finds the Book',
    subtitle:'A lost scroll triggers revival.',
    body:`<p>While renovating the Temple, the high priest finds a forgotten scroll of the Law. Young king Josiah tears his robes and weeps as it is read. He sweeps Judah clean of idols — but the judgment delayed for his sake will fall in his sons' days.</p>`,
    scriptureRefs:['2 Kings 22','2 Kings 23'] },
  { id:'jeremiah', year:-627, displayYear:'627 BC', era:'divided-kingdom',
    icon:'😢', title:'Jeremiah, the Weeping Prophet',
    subtitle:'Called before he was born.',
    body:`<p>"Before I formed you in the womb I knew you." Jeremiah preaches forty years to a nation that will not listen, watches his city burn, then is dragged to Egypt against his will. He also writes the promise: "I will write my law on their hearts."</p>`,
    scriptureRefs:['Jeremiah 1:5','Jeremiah 31:31-34'] },

  // ── ACT 7: EXILE & RETURN ─────────────────────────────────
  { id:'jerusalem-falls', year:-586, displayYear:'586 BC', era:'exile-return',
    icon:'🔥', title:'Jerusalem Falls to Babylon',
    subtitle:'Temple burns. Judah exiled.',
    body:`<p>Nebuchadnezzar destroys the Temple, burns the city, takes Judah captive. The exile begins. "By the rivers of Babylon, there we sat down and wept when we remembered Zion."</p>`,
    scriptureRefs:['2 Kings 25','Psalm 137'] },
  { id:'ezekiel-bones', year:-585, displayYear:'~585 BC', era:'exile-return',
    icon:'💀', title:"Ezekiel's Valley of Dry Bones",
    subtitle:'Prophesy to the wind.',
    body:`<p>Ezekiel is set down in a valley full of bones — "very many, and very dry." He prophesies; they rattle, knit, rise, breathe. A stunning picture of resurrection — for exiled Israel, and for everyone after.</p>`,
    scriptureRefs:['Ezekiel 37:1-14'] },
  { id:'fiery-furnace', year:-580, displayYear:'~580 BC', era:'exile-return',
    icon:'🔥', title:'Shadrach, Meshach & Abednego',
    subtitle:'"Even if He does not, we will not bow."',
    body:`<p>Three Hebrew exiles refuse to worship Nebuchadnezzar's statue. Heated seven times hotter, the furnace kills its stokers but not them — and a fourth figure walks among them in the flames. "Like a son of the gods," the king says.</p>`,
    scriptureRefs:['Daniel 3'] },
  { id:'daniel', year:-560, displayYear:'~560 BC', era:'exile-return',
    icon:'🦁', title:"Daniel in the Lions' Den",
    subtitle:'Faith refined in foreign fire.',
    body:`<p>Faithful in three empires across seventy years. The lions' den. Visions of beasts and the Son of Man receiving an eternal kingdom. God preserves a witness in the heart of the empire that destroyed Jerusalem.</p>`,
    scriptureRefs:['Daniel 6','Daniel 7:13-14'], relatedSiteId:'babylon' },
  { id:'cyrus-decree', year:-538, displayYear:'538 BC', era:'exile-return',
    icon:'🕊️', title:"Cyrus Sends Israel Home",
    subtitle:'God uses a Persian king.',
    body:`<p>Cyrus the Great signs the decree: Jewish exiles may return and rebuild the Temple. Isaiah named Cyrus by name 150 years before he was born. The first wave packs up and starts the long road home.</p>`,
    scriptureRefs:['Isaiah 45:1-7','Ezra 1'] },
  { id:'second-temple', year:-516, displayYear:'516 BC', era:'exile-return',
    icon:'🏛️', title:'Second Temple Rebuilt',
    subtitle:'Smaller, but God dwells again.',
    body:`<p>Twenty years after the foundation is laid — through opposition, fear, and discouragement — the Second Temple is finished. The old men weep; it cannot match Solomon's. The young rejoice; God is among them again.</p>`,
    scriptureRefs:['Ezra 6','Haggai 2'] },
  { id:'esther', year:-478, displayYear:'~478 BC', era:'exile-return',
    icon:'👸', title:'Esther Saves Her People',
    subtitle:'"For such a time as this."',
    body:`<p>A Jewish orphan becomes queen of Persia. When Haman plots genocide, Mordecai presses her: maybe you are queen for this very moment. She risks her life before the king. God's name is never mentioned in the book; His hand is everywhere.</p>`,
    scriptureRefs:['Esther 4:14','Esther 7'] },
  { id:'nehemiah-wall', year:-445, displayYear:'~445 BC', era:'exile-return',
    icon:'🧱', title:'Nehemiah Rebuilds the Wall',
    subtitle:'Prayer and a trowel.',
    body:`<p>The king's cupbearer hears Jerusalem still has no walls and weeps. He prays for months, then asks. The work takes 52 days against constant threats — workers wielding swords in one hand and tools in the other.</p>`,
    scriptureRefs:['Nehemiah 1','Nehemiah 6:15'] },
  { id:'ezra-law', year:-444, displayYear:'~444 BC', era:'exile-return',
    icon:'📜', title:'Ezra Reads the Law',
    subtitle:'A nation hears Scripture again.',
    body:`<p>From sunrise until midday, Ezra reads the Law aloud at the Water Gate. The people weep as they finally understand. Nehemiah says: "Do not mourn. The joy of the LORD is your strength." They feast that night.</p>`,
    scriptureRefs:['Nehemiah 8:1-12'] },
  { id:'malachi', year:-430, displayYear:'~430 BC', era:'exile-return',
    icon:'📚', title:'Malachi · The OT Closes',
    subtitle:'400 silent years begin.',
    body:`<p>The last prophet writes a final warning and a final promise: a messenger like Elijah will come to prepare the way for the LORD. The page turns. Heaven goes quiet for four centuries.</p>`,
    scriptureRefs:['Malachi 4:5-6'] },

  // ── ACT 8: SECOND TEMPLE / INTERTESTAMENTAL ───────────────
  { id:'septuagint', year:-250, displayYear:'~250 BC', era:'second-temple',
    icon:'📖', title:'The Septuagint',
    subtitle:'The Hebrew Scriptures go Greek.',
    body:`<p>In Alexandria under the Ptolemies, seventy Jewish scholars translate the Hebrew Bible into Greek. The "LXX" becomes the Bible of the diaspora — and the version most quoted by the New Testament writers three centuries later.</p>`,
    scriptureRefs:[] },
  { id:'maccabees', year:-165, displayYear:'~165 BC', era:'second-temple',
    icon:'⚔️', title:'The Maccabean Revolt',
    subtitle:'Faithful Jews defy Antiochus IV.',
    body:`<p>Antiochus Epiphanes desecrates the Temple — a pig sacrificed to Zeus on the altar. The priest Mattathias and his sons revolt. After three years of guerrilla war, Judah Maccabee retakes Jerusalem.</p>`,
    scriptureRefs:[] },
  { id:'hanukkah', year:-164, displayYear:'~164 BC', era:'second-temple',
    icon:'🕎', title:'The Temple Rededicated',
    subtitle:'A festival of lights begins.',
    body:`<p>The altar is rebuilt; the menorah relit. Tradition says one day's oil burned for eight. Hanukkah remembers it every winter. Jesus Himself walks Solomon's Colonnade during this Feast of Dedication.</p>`,
    scriptureRefs:['John 10:22-23'] },
  { id:'rome-judea', year:-63, displayYear:'63 BC', era:'second-temple',
    icon:'🦅', title:'Rome Takes Judea',
    subtitle:'Pompey enters the Holy of Holies.',
    body:`<p>The Roman general Pompey besieges Jerusalem and walks straight into the Most Holy Place, finding it empty. Judea becomes a client state of Rome — setting the political stage on which Jesus will be born.</p>`,
    scriptureRefs:[] },
  { id:'herod', year:-37, displayYear:'37 BC', era:'second-temple',
    icon:'🏯', title:'Herod the Great',
    subtitle:'A paranoid king rebuilds the Temple.',
    body:`<p>An Idumean king on a Jewish throne by Roman appointment. Brilliant, paranoid, brutal. He doubles the Temple Mount and rebuilds the sanctuary on a scale to rival Solomon's. He is still on the throne when Jesus is born.</p>`,
    scriptureRefs:['Matthew 2:1-18'], relatedSiteId:'temple-mount' },

  // ── ACT 9: JESUS ──────────────────────────────────────────
  { id:'birth', year:-4, displayYear:'~5 BC', era:'jesus-ministry',
    icon:'⭐', title:'Birth of Jesus',
    subtitle:'God enters time.',
    body:`<p>The angels sing over Bethlehem. Shepherds run to a stable. The Magi follow a star and bring gold, frankincense, myrrh. "The Word became flesh and dwelt among us, and we have seen His glory."</p>`,
    scriptureRefs:['Luke 2:1-20','John 1:14'], relatedSiteId:'bethlehem' },
  { id:'john-baptist', year:27, displayYear:'~27 AD', era:'jesus-ministry',
    icon:'🐪', title:'John the Baptist',
    subtitle:'A voice crying in the wilderness.',
    body:`<p>Camel's hair, locusts, wild honey. John preaches repentance and baptizes thousands in the Jordan. He is the messenger Malachi promised — preparing the way for One whose sandals he is not worthy to untie.</p>`,
    scriptureRefs:['Matthew 3:1-12','Isaiah 40:3'], relatedSiteId:'jordan-river' },
  { id:'baptism', year:28, displayYear:'~28 AD', era:'jesus-ministry',
    icon:'🕊️', title:"Jesus's Baptism",
    subtitle:'The Father affirms before the work begins.',
    body:`<p>Jesus enters the Jordan. The heavens tear open. The Spirit descends as a dove. The Father's voice: "This is my beloved Son, with whom I am well pleased." The Trinity together at the start of the mission.</p>`,
    scriptureRefs:['Matthew 3:13-17'], relatedSiteId:'jordan-river' },
  { id:'twelve-called', year:28, displayYear:'~28 AD', era:'jesus-ministry',
    icon:'⚓', title:'Calling the Twelve',
    subtitle:'"Follow me."',
    body:`<p>Fishermen drop their nets at a word. A tax collector leaves his booth. A zealot, a doubter, a betrayer-to-come. Jesus chooses an unlikely twelve and prays all night before naming them.</p>`,
    scriptureRefs:['Mark 1:16-20','Luke 6:12-16'] },
  { id:'sermon-mount', year:29, displayYear:'~29 AD', era:'jesus-ministry',
    icon:'⛰️', title:'Sermon on the Mount',
    subtitle:"The kingdom's constitution.",
    body:`<p>"Blessed are the poor in spirit." "Love your enemies." "Seek first the kingdom of God." Three chapters that turned the world's values upside down and have never been digested since.</p>`,
    scriptureRefs:['Matthew 5-7'] },
  { id:'feeding-5000', year:29, displayYear:'~29 AD', era:'jesus-ministry',
    icon:'🍞', title:'Feeding the 5,000',
    subtitle:'Five loaves, two fish, a kingdom picnic.',
    body:`<p>A boy's lunch in His hands. He looks to heaven, blesses, breaks, hands out — and keeps handing. Twelve baskets of leftovers. The crowd wants to crown Him; He withdraws. "I am the bread of life."</p>`,
    scriptureRefs:['John 6:1-15','John 6:35'] },
  { id:'transfiguration', year:29, displayYear:'~29 AD', era:'jesus-ministry',
    icon:'✨', title:'The Transfiguration',
    subtitle:'A flash of resurrection glory.',
    body:`<p>On a high mountain, Jesus's face shines like the sun. Moses and Elijah appear talking with Him. The Father's voice again: "This is my beloved Son — listen to Him." The disciples fall on their faces.</p>`,
    scriptureRefs:['Matthew 17:1-8'] },
  { id:'lazarus', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'⚱️', title:'Lazarus Raised',
    subtitle:'"I am the resurrection and the life."',
    body:`<p>Four days in the tomb. Mary and Martha grieving. Jesus weeps with them — then shouts at the grave: "Lazarus, come out!" The dead man walks out wrapped in his graveclothes. The crowd splits; the Sanhedrin starts planning.</p>`,
    scriptureRefs:['John 11:25','John 11:43-44'] },
  { id:'triumphal-entry', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🐴', title:'Triumphal Entry',
    subtitle:'A king on a donkey.',
    body:`<p>Palm Sunday. Cloaks and palm branches on the road. "Hosanna! Blessed is He who comes in the name of the LORD!" Jesus weeps over the city that will reject Him by Friday. The lamb walks into Jerusalem for Passover.</p>`,
    scriptureRefs:['Matthew 21:1-11','Zechariah 9:9'], relatedSiteId:'jerusalem' },
  { id:'last-supper', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🍞', title:'The Last Supper',
    subtitle:'A new covenant in bread and wine.',
    body:`<p>An upper room. Feet washed by the Master's hands. "This is my body, given for you. This cup is the new covenant in my blood." Judas leaves into the night. Peter swears he will never deny.</p>`,
    scriptureRefs:['Luke 22:14-23','John 13:1-17'] },
  { id:'gethsemane', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🌿', title:'Gethsemane',
    subtitle:'"Not my will, but yours."',
    body:`<p>An olive press at the foot of the Mount of Olives. Drops of blood-sweat in the dirt. Three times He prays. "Father, if it is possible, let this cup pass." A kiss. Soldiers. The disciples scatter.</p>`,
    scriptureRefs:['Matthew 26:36-46','Luke 22:44'], relatedSiteId:'mount-of-olives' },
  { id:'crucifixion', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'✝️', title:'The Crucifixion',
    subtitle:'It is finished.',
    body:`<p>The Lamb of God takes away the sin of the world. Three hours of darkness over the land. The Temple veil tears top to bottom. "Father, into your hands I commit my spirit." Heaven's payment in full.</p>`,
    scriptureRefs:['John 19','Isaiah 53'], relatedSiteId:'garden-tomb' },
  { id:'resurrection', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🌅', title:'The Resurrection',
    subtitle:'Death loses.',
    body:`<p>Sunday at dawn. The stone rolled away. Angels. The empty tomb. "He is not here, He is risen — just as He said." Mary first, then Peter, then five hundred at once. History's hinge swings open.</p>`,
    scriptureRefs:['Matthew 28','1 Corinthians 15:3-8'], relatedSiteId:'garden-tomb' },
  { id:'ascension', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'☁️', title:'The Ascension',
    subtitle:'Jesus is enthroned.',
    body:`<p>Forty days of resurrection appearances. Then on the Mount of Olives, Jesus rises into a cloud. Two angels stand by the gaping disciples: "He will return in the same way you saw Him go."</p>`,
    scriptureRefs:['Acts 1:9-11'], relatedSiteId:'mount-of-olives' },

  // ── ACT 10: APOSTOLIC ─────────────────────────────────────
  { id:'pentecost', year:30, displayYear:'30 AD', era:'pauline-journeys',
    icon:'🔥', title:'Pentecost',
    subtitle:'The Spirit is poured out. The church is born.',
    body:`<p>A sound like a violent wind. Tongues like fire over each disciple. They speak in every language gathered for the feast. Peter preaches; three thousand believe in a single day. The mission begins.</p>`,
    scriptureRefs:['Acts 2'], relatedSiteId:'jerusalem' },
  { id:'stephen', year:34, displayYear:'~34 AD', era:'pauline-journeys',
    icon:'🪨', title:'Stephen — First Martyr',
    subtitle:'"Lord, do not hold this sin against them."',
    body:`<p>The first deacon faces the Sanhedrin with a sermon stretching from Abraham to the cross. Stones fly. A young man named Saul holds the coats. Stephen dies forgiving, "looking up to heaven" at Jesus standing to receive him.</p>`,
    scriptureRefs:['Acts 7'] },
  { id:'paul-conversion', year:34, displayYear:'~34 AD', era:'pauline-journeys',
    icon:'⚡', title:"Paul's Conversion",
    subtitle:'The persecutor becomes the apostle.',
    body:`<p>On the road to Damascus, Saul is blinded by light and meets the risen Christ: "Why do you persecute me?" Three days of darkness, then sight through Ananias's hands. The greatest theologian of the New Testament begins.</p>`,
    scriptureRefs:['Acts 9:1-22'], relatedSiteId:'damascus' },
  { id:'cornelius', year:40, displayYear:'~40 AD', era:'pauline-journeys',
    icon:'🛐', title:'Cornelius — Gospel to the Gentiles',
    subtitle:'A Roman centurion receives the Spirit.',
    body:`<p>Peter sees a vision of unclean animals — three times. He travels to Caesarea, preaches Christ to a Roman household, and the Spirit falls on them mid-sermon. The wall comes down. The mission is for everyone.</p>`,
    scriptureRefs:['Acts 10','Acts 11:18'] },
  { id:'paul-first-journey', year:46, displayYear:'~46 AD', era:'pauline-journeys',
    icon:'⛵', title:"Paul's First Journey",
    subtitle:'The gospel goes to the nations.',
    body:`<p>The Antioch church sends Paul and Barnabas to Cyprus and Asia Minor. Cities are reached, churches planted, riots survived. Jews and Gentiles, slaves and free, sit at the same Lord's Table for the first time.</p>`,
    scriptureRefs:['Acts 13','Acts 14'], relatedSiteId:'antioch' },
  { id:'jerusalem-council', year:50, displayYear:'~50 AD', era:'pauline-journeys',
    icon:'🤝', title:'The Council of Jerusalem',
    subtitle:'Gentiles enter the church without becoming Jewish.',
    body:`<p>Must Gentile believers be circumcised and keep Moses' law? The apostles, elders, and the Holy Spirit say no — grace is enough. The letter goes out to the churches. The gospel stays the gospel.</p>`,
    scriptureRefs:['Acts 15:1-29'] },
  { id:'romans-written', year:57, displayYear:'~57 AD', era:'pauline-journeys',
    icon:'📜', title:'Romans Written',
    subtitle:"The gospel's deepest exposition.",
    body:`<p>From Corinth, Paul writes to a church he hasn't yet visited. "I am not ashamed of the gospel — it is the power of God for salvation to everyone who believes." Sixteen chapters that have reshaped the world.</p>`,
    scriptureRefs:['Romans 1:16-17'], relatedSiteId:'rome' },
  { id:'paul-rome', year:60, displayYear:'~60 AD', era:'pauline-journeys',
    icon:'⚓', title:'Paul Reaches Rome',
    subtitle:'Under house arrest. Still preaching.',
    body:`<p>Storm-shipwrecked on Malta, then on to the capital of the empire. Acts ends with Paul "preaching the kingdom of God and teaching about the Lord Jesus Christ — with all boldness and without hindrance."</p>`,
    scriptureRefs:['Acts 28:30-31'], relatedSiteId:'rome' },
  { id:'james-martyred', year:62, displayYear:'~62 AD', era:'pauline-journeys',
    icon:'🕯️', title:'James of Jerusalem Martyred',
    subtitle:'The brother of Jesus dies for the Lord he once doubted.',
    body:`<p>James — head of the Jerusalem church, author of the epistle — is thrown from the Temple parapet and clubbed to death. He prays for his killers as he dies. Tradition remembers his knees calloused like a camel's from prayer.</p>`,
    scriptureRefs:['James 5:7-11'] },
  { id:'peter-paul-killed', year:67, displayYear:'~67 AD', era:'pauline-journeys',
    icon:'⚔️', title:'Peter & Paul Martyred',
    subtitle:'Two apostles, two crowns.',
    body:`<p>Under Nero's persecution: Peter crucified upside-down outside Rome, refusing to die as his Lord did; Paul beheaded outside the same walls. "I have fought the good fight, I have finished the race, I have kept the faith."</p>`,
    scriptureRefs:['2 Timothy 4:7-8'] },
  { id:'jerusalem-70', year:70, displayYear:'70 AD', era:'pauline-journeys',
    icon:'💥', title:'Jerusalem Falls Again',
    subtitle:'The Temple is destroyed. Forever.',
    body:`<p>Roman legions under Titus encircle Jerusalem. The Temple burns. Jesus had wept over this exact moment forty years earlier. The animal sacrifice ends — because the final Sacrifice has been offered.</p>`,
    scriptureRefs:['Matthew 24:2','Hebrews 10:11-14'] },
  { id:'patmos', year:95, displayYear:'~95 AD', era:'pauline-journeys',
    icon:'📖', title:'Revelation Written',
    subtitle:'John sees the end of the story.',
    body:`<p>Exiled to Patmos under Domitian, the last living apostle receives the Revelation: Christ in glory, the seven churches, the Lamb on the throne, the final victory. "Behold, I make all things new."</p>`,
    scriptureRefs:['Revelation 1:9','Revelation 21:5'], relatedSiteId:'patmos' },

  // ── ACT 11: WAITING (we are here) ─────────────────────────
  { id:'present', year:2026, displayYear:'Now', era:'present',
    icon:'⏳', title:'You Are Here',
    subtitle:'Between resurrection and return.',
    body:`<p>The story is not over. Two thousand years of waiting, growing, suffering, witnessing. The same Spirit that filled the upper room fills the church today. The same Jesus who promised to return is preparing a place.</p>`,
    scriptureRefs:['Revelation 22:20'] },
  { id:'return', year:9999, displayYear:'When?', era:'future',
    icon:'👑', title:"Christ's Return",
    subtitle:'Every knee will bow.',
    body:`<p>"In the same way you saw Him go." Every eye will see Him. Every wrong made right. The new heavens and the new earth. "He will wipe away every tear from their eyes." This is where the whole Bible has been pointing.</p>`,
    scriptureRefs:['Acts 1:11','Revelation 21:1-5','Philippians 2:10-11'] },
];

if (typeof window !== 'undefined') {
  window.BIBLE_TIMELINE_EVENTS = BIBLE_TIMELINE_EVENTS;
}
